using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed: GetTypeInfo<T> returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata  : {personInfo.Type.Name} (kind: {personInfo.Kind})");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Round-trip serialize : {json}");

Person p = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Round-trip deserialize: Name={p.Name}, Age={p.Age}");

// 2) Probe without throwing: TryGetTypeInfo
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"\nTryGet Person       : found ({found!.Type.Name})");

if (!options.TryGetTypeInfo(typeof(Secret), out _))
    Console.WriteLine("TryGet Secret       : not found (no exception thrown)");

// --- types ---
record Person(string Name, int Age);

[JsonSerializable(typeof(Secret))]   // metadata lives in a *different* context
partial class SecretContext : JsonSerializerContext;

class Secret { public int Key { get; set; } }

